INSERT INTO email_verification_code(
    email, purpose, code_hash, expires_at, attempt_count, send_ip, created_at, updated_at
)
VALUES (
    #{email}, #{purpose}, #{codeHash}, #{expiresAt}, #{attemptCount}, #{sendIp}, NOW(), NOW()
)

mapper.select:
SELECT *
FROM email_verification_code
WHERE email = #{email}
  AND purpose = #{purpose}
  AND used_at IS NULL
  AND expires_at > #{now}
ORDER BY id DESC
LIMIT 1

SELECT COUNT(*)
FROM email_verification_code
WHERE email = #{email}
  AND purpose = #{purpose}
  AND created_at >= #{since}

mapper.update:
UPDATE email_verification_code
SET used_at = NOW(), updated_at = NOW()
WHERE id = #{id}

UPDATE email_verification_code
SET attempt_count = attempt_count + 1, updated_at = NOW()
WHERE id = #{id}
